SELECT id, sender_id AS senderId, sender_name AS senderName,
       channel, content, create_time AS createTime, target_id AS targetId
FROM chat_message
WHERE channel = #{channel} AND server_id = #{serverId}
ORDER BY create_time DESC
LIMIT #{limit}

SELECT id, sender_id AS senderId, sender_name AS senderName,
       channel, content, create_time AS createTime, target_id AS targetId
FROM chat_message
WHERE channel = #{channel} AND server_id = #{serverId} AND create_time > #{sinceTime}
ORDER BY create_time ASC
LIMIT #{limit}

SELECT id, sender_id AS senderId, sender_name AS senderName,
       channel, content, create_time AS createTime
FROM chat_message
WHERE channel = 'nation' AND server_id = #{serverId} AND nation_id = #{nationId}
ORDER BY create_time DESC
LIMIT #{limit}

SELECT id, sender_id AS senderId, sender_name AS senderName,
       channel, content, create_time AS createTime
FROM chat_message
WHERE channel = 'nation' AND server_id = #{serverId} AND nation_id = #{nationId}
      AND create_time > #{sinceTime}
ORDER BY create_time ASC
LIMIT #{limit}

SELECT id, sender_id AS senderId, sender_name AS senderName,
       channel, content, create_time AS createTime
FROM chat_message
WHERE channel = 'alliance' AND server_id = #{serverId} AND alliance_id = #{allianceId}
ORDER BY create_time DESC
LIMIT #{limit}

SELECT id, sender_id AS senderId, sender_name AS senderName,
       channel, content, create_time AS createTime
FROM chat_message
WHERE channel = 'alliance' AND server_id = #{serverId} AND alliance_id = #{allianceId}
      AND create_time > #{sinceTime}
ORDER BY create_time ASC
LIMIT #{limit}

SELECT id, sender_id AS senderId, sender_name AS senderName,
       channel, content, create_time AS createTime, target_id AS targetId
FROM chat_message
WHERE channel = 'private' AND server_id = #{serverId}
      AND (sender_id = #{userId} OR target_id = #{userId})
      AND create_time > #{sinceTime}
ORDER BY create_time ASC
LIMIT #{limit}
